    {
      MagickRealType gamma;
      MagickRealType length;
      MagickRealType offset;
      MagickRealType scale;
      PointInfo p;
      PointInfo q;
      const SegmentInfo *gradient_vector;
      gradient_vector = &gradient->gradient_vector;
