inline static void ConvertRGBToCMYK(MagickPixelPacket *pixel)
{
  MagickRealType black;
  MagickRealType cyan;
  MagickRealType magenta;
  MagickRealType yellow;
  if (((pixel->red == 0) && (pixel->green == 0)) && (pixel->blue == 0))
  {
